#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=1000005,mod=1e9+7;
ll n,a[N],jc[N];
ll qp(ll x,ll y)
{
    ll ans=1;
    while(y)
    {
        if(y%2) ans=(ans*x)%mod;
        x=(x*x)%mod;
        y/=2;
    }
    return ans;
}
ll c(ll x,ll y)
{
    return jc[x]*qp((jc[x-y]%mod)*jc[y]%mod,mod-2)%mod;
}
ll ans=1;
void init()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        a[i]/=2;
    }
    jc[0]=1;
    for(int i=1;i<=(N-5);i++)
    {
        jc[i]=jc[i-1]*i%mod;
    }
}
int main()
{
    init();
    for(int i=1;i<n;i++)
    {
        int xia=a[i],shang=a[i+1];
        if(shang>=xia)
        {
            ans=(ans*c(shang-1,xia-1))%mod;
        }
        else ans=(ans*c(xia,shang))%mod;
    }
    cout<<ans;
    return 0;
}
